import java.io.*;
import java.util.*;

public class Main {
    enum HTTPStatus {
        OK(200,"OK"),
        CREATED(201,"Created"),
        BAD_REQUEST(400,"Bad Request"),
        UNAUTHORIZED(401,"Unauthorized"),
        FORBIDDEN(403,"Forbidden"),
        NOT_FOUND(404,"Not Found"),
        INTERNAL_SERVER_ERROR(500,"Internal Server Error");
        private final int code;
        private final String message;
        private static final Map<Integer,HTTPStatus> map = new HashMap<>();
        static { for(HTTPStatus s: values()) map.put(s.code,s); }
        HTTPStatus(int c,String m){ this.code=c; this.message=m; }
        public static String getMessage(int c){ HTTPStatus s = map.get(c); return s==null?"Unknown Status Code":s.message; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<T;i++){
            int code = Integer.parseInt(br.readLine().trim());
            sb.append(code).append(": ").append(HTTPStatus.getMessage(code)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

